#!/usr/bin/env node
/**
 * Capture all documentation screenshots for docs/website/images/.
 *
 * Driven by tools/capture-map.json (one entry per screenshot, generated by
 * the inventory audit). Each entry declares:
 *   - path:      where to save (relative to docs/website/images/)
 *   - surface:   'customizer' | 'frontend' | 'unknown'
 *   - target:    customizer autofocus query OR frontend pathname
 *   - prep:      optional state hint (e.g. 'logout', 'set color_scheme_preset=sapphire')
 *   - viewport:  '1200x900' (the wp.org screenshot.png spec; protocol default)
 *   - dark:      true if the capture should be done in dark mode
 *
 * Run:
 *   npm install --save-dev playwright
 *   node tools/capture-screenshots.mjs [--filter=customizer-site-skin] [--dry-run]
 *
 * Prerequisites:
 *   - Local site at http://buddyx.local (or set BUDDYX_BASE_URL)
 *   - Autologin mu-plugin installed so the script can authenticate via
 *     ?autologin=1 (or set BUDDYX_AUTOLOGIN_KEY)
 *   - Active theme: buddyx (free) — verify with `wp theme list --status=active --field=name`
 *   - Demo content loaded (the script does NOT reset customizer values;
 *     run with a clean DB if shooting baseline / defaults)
 *
 * Outputs:
 *   - PNG files in docs/website/images/, then converts to WebP
 *     (requires the `cwebp` binary from libwebp; install via brew or apt)
 *
 * Exits non-zero if any capture fails.
 */

import { chromium } from 'playwright';
import { execFileSync } from 'node:child_process';
import { mkdirSync, readFileSync, unlinkSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------

const __dirname = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = join(__dirname, '..');
const MAP_PATH  = join(REPO_ROOT, 'tools', 'capture-map.json');
const IMAGES_DIR = join(REPO_ROOT, 'docs', 'website', 'images');

const BASE_URL       = process.env.BUDDYX_BASE_URL || 'http://buddyx.local';
const AUTOLOGIN_KEY  = process.env.BUDDYX_AUTOLOGIN_KEY || 'autologin=1';
const WEBP_QUALITY   = parseInt(process.env.BUDDYX_WEBP_QUALITY || '80', 10);
const SETTLE_MS      = parseInt(process.env.BUDDYX_SETTLE_MS || '800', 10);

// CLI flags
const argv = process.argv.slice(2);
const filterFlag = argv.find(a => a.startsWith('--filter='));
const FILTER = filterFlag ? filterFlag.slice('--filter='.length) : null;
const DRY_RUN = argv.includes('--dry-run');
const VERBOSE = argv.includes('--verbose') || argv.includes('-v');

function log(msg) {
  if (VERBOSE) console.log(`[capture] ${msg}`);
}

// ---------------------------------------------------------------------------
// Cwebp availability check (execFile - no shell interpretation)
// ---------------------------------------------------------------------------

function hasCwebp() {
  try {
    execFileSync('cwebp', ['-version'], { stdio: 'pipe' });
    return true;
  } catch {
    return false;
  }
}

// ---------------------------------------------------------------------------
// Capture-map loading + filtering
// ---------------------------------------------------------------------------

const capture_map = JSON.parse(readFileSync(MAP_PATH, 'utf8'));

let entries = capture_map.filter(e => e.surface !== 'unknown');
if (FILTER) {
  entries = entries.filter(e => e.path.includes(FILTER));
  console.log(`[capture] filter=${FILTER} narrows ${capture_map.length} -> ${entries.length} entries`);
}

if (entries.length === 0) {
  console.error('[capture] no entries to process after filtering');
  process.exit(1);
}

console.log(`[capture] target site:   ${BASE_URL}`);
console.log(`[capture] entries:       ${entries.length}`);
console.log(`[capture] dry-run:       ${DRY_RUN ? 'YES' : 'no'}`);
console.log(`[capture] webp quality:  ${WEBP_QUALITY}`);
console.log(`[capture] cwebp:         ${hasCwebp() ? 'present' : 'MISSING (install libwebp before running real captures)'}`);

if (DRY_RUN) {
  console.log('\n[capture] DRY RUN - listing what would happen:');
  for (const e of entries) {
    const url = e.surface === 'customizer'
      ? `${BASE_URL}/wp-admin/customize.php${e.target}`
      : `${BASE_URL}${e.target}`;
    console.log(`  ${e.path}  surface=${e.surface}  url=${url}  prep=${e.prep || '-'}`);
  }
  process.exit(0);
}

// ---------------------------------------------------------------------------
// Browser lifecycle
// ---------------------------------------------------------------------------

const [VIEWPORT_W, VIEWPORT_H] = (entries[0]?.viewport || '1200x900').split('x').map(Number);

const browser = await chromium.launch({ headless: true });
const context = await browser.newContext({
  viewport: { width: VIEWPORT_W, height: VIEWPORT_H },
  deviceScaleFactor: 1,        // 1x DPR per the protocol (smaller files; docs don't need Retina)
  colorScheme: 'light',         // baseline; overridden per-entry for dark captures
});
const page = await context.newPage();

// Trip the autologin mu-plugin once per session (puts admin cookie in context).
log(`authenticating via ${BASE_URL}/?${AUTOLOGIN_KEY}`);
const authResp = await page.goto(`${BASE_URL}/?${AUTOLOGIN_KEY}`, { waitUntil: 'networkidle' });
if (!authResp || !authResp.ok()) {
  console.error(`[capture] autologin failed: ${authResp?.status()}. Ensure the mu-plugin is installed and BUDDYX_AUTOLOGIN_KEY matches its query string.`);
  process.exit(2);
}

// ---------------------------------------------------------------------------
// Capture loop
// ---------------------------------------------------------------------------

let ok = 0;
let failed = [];

for (const e of entries) {
  const outPath = join(IMAGES_DIR, e.path);
  const tmpPng  = outPath.replace(/\.webp$/, '.tmp.png');

  // Ensure directory exists
  mkdirSync(dirname(outPath), { recursive: true });

  // Build target URL
  const url = e.surface === 'customizer'
    ? `${BASE_URL}/wp-admin/customize.php${e.target.startsWith('?') || e.target.startsWith('/') ? e.target : '?' + e.target}`
    : `${BASE_URL}${e.target}`;

  // Frontend captures should be done logged-out (prevents the 32px admin-bar reserve)
  if (e.surface === 'frontend' && /^logout/.test(e.prep || '')) {
    log(`logging out before ${e.path}`);
    await context.clearCookies();
    // (Re-login at the end of the loop if more customizer captures follow)
  }

  // Dark-mode toggle if requested
  if (e.dark) {
    await page.emulateMedia({ colorScheme: 'dark' });
  } else {
    await page.emulateMedia({ colorScheme: 'light' });
  }

  // Pre-prime localStorage on the target origin for color-mode requests
  // BEFORE navigating, so the first-paint inline script picks it up and
  // there is no FOUC in the captured frame.
  if (e.dark && e.surface === 'frontend') {
    try {
      // Land on the origin first (any URL on the same host works) so we
      // can write to localStorage. About:blank does not share storage.
      await page.goto(`${BASE_URL}/`, { waitUntil: 'domcontentloaded', timeout: 15000 });
      await page.evaluate(() => {
        try { localStorage.setItem('bx-color-mode', 'dark'); } catch (_) {}
      });
      log(`pre-set localStorage bx-color-mode=dark for ${e.path}`);
    } catch (err) {
      log(`localStorage prep failed (continuing): ${err.message}`);
    }
  }

  // Optional declarative prep steps. Use this when prep needs an actual
  // DOM action (scroll, click) — declared in capture-map.json under
  // `prep_action: { type: '...', selector?: '...', x?: 0, y?: 0 }`.
  // Supported types: 'scroll' (y or selector), 'click' (selector), 'wait' (ms).
  const prep_action = e.prep_action;

  log(`navigating to ${url}`);
  try {
    await page.goto(url, { waitUntil: 'networkidle', timeout: 30000 });
    // Let any customizer JS finish hydrating + live-preview updates settle
    await page.waitForTimeout(SETTLE_MS);

    if (prep_action) {
      if (prep_action.type === 'scroll') {
        if (prep_action.selector) {
          await page.locator(prep_action.selector).first().scrollIntoViewIfNeeded({ timeout: 5000 });
        } else if (typeof prep_action.y === 'number') {
          await page.evaluate(y => window.scrollTo(0, y), prep_action.y);
        }
        await page.waitForTimeout(300);
      } else if (prep_action.type === 'click') {
        await page.locator(prep_action.selector).first().click({ timeout: 5000 });
        await page.waitForTimeout(SETTLE_MS);
      } else if (prep_action.type === 'wait') {
        await page.waitForTimeout(prep_action.ms || 500);
      }
    }

    await page.screenshot({ path: tmpPng, fullPage: false });
  } catch (err) {
    failed.push({ path: e.path, error: err.message });
    console.error(`[capture] FAIL ${e.path}: ${err.message}`);
    continue;
  }

  // Convert PNG -> WebP via execFile (no shell, no injection surface)
  if (hasCwebp()) {
    try {
      execFileSync('cwebp', ['-q', String(WEBP_QUALITY), tmpPng, '-o', outPath], { stdio: 'pipe' });
      unlinkSync(tmpPng);
    } catch (err) {
      console.error(`[capture] cwebp FAIL ${e.path}: ${err.message}`);
      failed.push({ path: e.path, error: 'cwebp conversion failed' });
      continue;
    }
  } else {
    // No cwebp - leave the PNG and warn; future commit can batch-convert
    console.warn(`[capture] WARN ${e.path}: cwebp missing, left PNG at ${tmpPng}`);
  }

  ok++;
  if (ok % 10 === 0) {
    console.log(`[capture] progress: ${ok}/${entries.length}`);
  }

  // Re-authenticate if we're switching back from a frontend capture
  if (e.surface === 'frontend') {
    await page.goto(`${BASE_URL}/?${AUTOLOGIN_KEY}`, { waitUntil: 'networkidle' });
  }
}

await browser.close();

// ---------------------------------------------------------------------------
// Report
// ---------------------------------------------------------------------------

console.log(`\n[capture] DONE`);
console.log(`[capture]   ok:     ${ok}`);
console.log(`[capture]   failed: ${failed.length}`);

if (failed.length) {
  console.log(`\n[capture] FAILED entries:`);
  for (const f of failed) console.log(`  ${f.path}  reason=${f.error}`);
  process.exit(3);
}

console.log(`\n[capture] Review the changes:`);
console.log(`  git diff --stat docs/website/images/`);
console.log(`  git add docs/website/images/`);
console.log(`  git commit -m "docs(images): re-shoot against 5.1.0 ($(date +%F))"`);
